Use ASP.NET Core's `WebApplicationFactory<T>` to host your server in-process and test MCP requests over HTTP without a real network listener:

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using Xunit;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test-client", version = "1.0" },
                capabilities = new { }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26", body.GetProperty("result")
            .GetProperty("protocolVersion").GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // Initialize first (required by MCP)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(body.GetProperty("result")
            .GetProperty("isError").GetBoolean());
    }
}
```

**Key points:**

- **`WebApplicationFactory<Program>`** boots your app in-memory with the full middleware pipeline — no port binding needed.
- **Override services** via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles (e.g., mock databases).
- **Stateful sessions (SSE/Streamable HTTP):** If your server uses session headers (`Mcp-Session-Id`), capture it from the `initialize` response and attach it to subsequent requests.
- **Notifications:** For testing server-sent events, use `HttpCompletionOption.ResponseHeadersRead` and read the stream incrementally.

This gives you full protocol-level coverage (JSON-RPC framing, headers, status codes) with the speed of an in-process test.
